import{_ as i,c as s,o as e,aj as t}from"./chunks/framework.VtnL2jmu.js";const g=JSON.parse('{"title":"tldr命令行极简说明书","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/tldr命令行极简说明书.md","filePath":"Linux/tldr命令行极简说明书.md"}'),l={name:"Linux/tldr命令行极简说明书.md"};function d(r,a,n,o,h,p){return e(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="tldr命令行极简说明书" tabindex="-1">tldr命令行极简说明书 <a class="header-anchor" href="#tldr命令行极简说明书" aria-label="Permalink to “tldr命令行极简说明书”">​</a></h1><h3 id="_1-为什么需要-tldr" tabindex="-1">1. 为什么需要 tldr？ <a class="header-anchor" href="#_1-为什么需要-tldr" aria-label="Permalink to “1. 为什么需要 tldr？”">​</a></h3><p>在 Linux 里，传统的 <code>man</code> 命令（Manual pages）虽然权威，但太像“法律条文”了——内容多、废话长、找个示例得翻好几屏。</p><p><strong>tldr</strong> 的全称是 <em>Too Long; Didn&#39;t Read</em>（太长不看）。它的核心理念是：<strong>不废话，只给最常用的命令示例。</strong></p><hr><h3 id="_2-安装-继续贯彻-pipx-隔离理念" tabindex="-1">2. 安装（继续贯彻 pipx 隔离理念） <a class="header-anchor" href="#_2-安装-继续贯彻-pipx-隔离理念" aria-label="Permalink to “2. 安装（继续贯彻 pipx 隔离理念）”">​</a></h3><p>虽然 <code>apt</code> 也能装，但为了保持环境纯净和版本最新，我们依然用 <code>pipx</code>：</p><div class="language-Bash"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pipx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tldr</span></span></code></pre></div><p><strong>初始化（重要）：</strong></p><p>安装完后，需要下载最新的命令缓存（第一次可能稍慢）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>tldr --update</span></span></code></pre></div><hr><h3 id="_3-实战场景-当你在开发中-断片-时" tabindex="-1">3. 实战场景：当你在开发中“断片”时 <a class="header-anchor" href="#_3-实战场景-当你在开发中-断片-时" aria-label="Permalink to “3. 实战场景：当你在开发中“断片”时”">​</a></h3><p>作为全栈开发，有些命令一个月才用一次，最容易忘。这时候 tldr 就救命了：</p><h4 id="场景-a-想压缩-解压文件-但记不住-tar-的参数" tabindex="-1">场景 A：想压缩/解压文件，但记不住 <code>tar</code> 的参数 <a class="header-anchor" href="#场景-a-想压缩-解压文件-但记不住-tar-的参数" aria-label="Permalink to “场景 A：想压缩/解压文件，但记不住 tar 的参数”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>tldr tar</span></span></code></pre></div><p>它会直接告诉你：</p><ul><li><p><code>tar -cf target.tar source</code> (压缩)</p></li><li><p><code>tar -xf source.tar</code> (解压)</p><p>没有那些深奥的原理，只有直接能用的命令。</p></li></ul><h4 id="场景-b-忘了怎么用-find-找特定的-java-文件" tabindex="-1">场景 B：忘了怎么用 <code>find</code> 找特定的 Java 文件 <a class="header-anchor" href="#场景-b-忘了怎么用-find-找特定的-java-文件" aria-label="Permalink to “场景 B：忘了怎么用 find 找特定的 Java 文件”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>tldr find</span></span></code></pre></div><p>它会列出：</p><ul><li>按扩展名找：<code>find . -name &quot;*.java&quot;</code></li><li>按目录找：<code>find . -type d -name &quot;src&quot;</code></li></ul><h4 id="场景-c-想看-lsof-怎么查端口占用-spring-boot-启动报错端口被占时" tabindex="-1">场景 C：想看 <code>lsof</code> 怎么查端口占用（Spring Boot 启动报错端口被占时） <a class="header-anchor" href="#场景-c-想看-lsof-怎么查端口占用-spring-boot-启动报错端口被占时" aria-label="Permalink to “场景 C：想看 lsof 怎么查端口占用（Spring Boot 启动报错端口被占时）”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>tldr lsof</span></span></code></pre></div><p>直接给示例：<code>lsof -i :8888</code></p><hr><h3 id="_4-进阶-配置中文支持" tabindex="-1">4. 进阶：配置中文支持 <a class="header-anchor" href="#_4-进阶-配置中文支持" aria-label="Permalink to “4. 进阶：配置中文支持”">​</a></h3><p>既然你偏好简体中文，<code>tldr</code> 是支持中文页面的，可以让它首选中文输出。</p><ol><li><p><strong>临时查看中文</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>tldr -L zh tar</span></span></code></pre></div></li><li><p><strong>永久设置</strong>：</p><p>在你的 <code>~/.bashrc</code> 中添加环境变量：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>export TLDR_LANGUAGE=&quot;zh&quot;</span></span></code></pre></div><p>然后执行 <code>source ~/.bashrc</code>。</p></li></ol>',29)])])}const k=i(l,[["render",d]]);export{g as __pageData,k as default};
